#!/usr/bin/env bash
# general-playbook.sh — 通用 Playbook 决策助手 for 侍酒师与葡萄酒.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="侍酒师与葡萄酒"
TOPIC="通用 Playbook"

usage() {
  cat <<EOF
general-playbook.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 4 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./general-playbook.sh             # interactive
  ./general-playbook.sh --dry-run   # walk through but no file
  ./general-playbook.sh --json      # JSON to stdout
  ./general-playbook.sh --explain   # show backing playbook rules + mental models
  ./general-playbook.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 通用 Playbook 主题下的 playbook 规则组合成交互树。

基于 4 条规则:
  • 如果 要判品质 / 解读分数 → 则 看「谁打分 + 什么风格偏好 + 利益位置」,**绝不看裸分 / 聚合分**;判信源先判其 bucket(一手 / 二手
  • 如果 要给一道菜配酒 → 则 先定菜的主导维度(脂 / 酸 / 甜 / 辣 / 蛋白)再套交互原则(酸配脂、单宁配蛋白、地配地、甜配甜),**配「菜的
  • 如果 要决定是否醒酒 / 怎么服务 → 则 **不是所有酒都醒**——只老酒去沉淀 / 年轻封闭的高单宁酒增氧,且拔塞「透气」瓶颈面积太小几乎不增氧、要真醒必须倒进
  • 如果 遇到厂商话术(95 分 = 客观最好 / 自然酒不上头 / sulfites 致头疼 / 投资酒稳赚 / 越老越好) → 则 默认是被资深拒绝的错位包装、回到机理。案例(case):红酒头疼真因更可能是 quercetin 抑制 ALDH 而非 

相关心智模型:
  • terroir-first（地理是第一性问题,旧世界尤甚）: 遇到一支酒,资深人的**第一个问题不是「什么品种 / 好不好喝」,而是「它来自哪——那块地的气 / 土 / 人为传统如何」**;terroir(风土)是不可复制、不可移植的组织原语,旧世界直接「以产地
  • codifiable 理论层 ⇄ tacit 校准层（双层不可互替）: 葡萄酒认知是**两层**——可背诵的理论(产区 / 法规 / 品种 / 酿造化学)和不可言传的校准(味觉记忆 / 盲品 / 侍酒服务);两层**不可互相替代**,读一百本书也代替不了真酒重复。

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "要判品质 / 解读分数"
  "要给一道菜配酒"
  "要决定是否醒酒 / 怎么服务"
  "遇到厂商话术(95 分 = 客观最好 / 自然酒不上头 / sulfites 致头疼 / 投资酒稳赚 / 越老越好)"
)
declare -a RULE_ACTIONS=(
  "看「谁打分 + 什么风格偏好 + 利益位置」,**绝不看裸分 / 聚合分**;判信源先判其 bucket(一手 / 二手 / 众包)。案例(case):Wine-Searcher 聚合分摊平了 critic 个体偏好;100 分制系统性偏爱 fruit bomb;Vivino 均分受甜度 / 价格 / 品牌污染,只看大众接受度不作专业品质依据 (evidence: [T02-S005, T06-S032])"
  "先定菜的主导维度(脂 / 酸 / 甜 / 辣 / 蛋白)再套交互原则(酸配脂、单宁配蛋白、地配地、甜配甜),**配「菜的整体」(酱汁 / 烹法)而非单一蛋白**。案例(case):同一块鱼黄油煎 vs 清蒸配酒完全不同,酱汁常比主料更决定配酒;经典反直觉如 Sauternes 配 Roquefort 蓝纹(甜咸对冲) (evidence: [T03-S010, T03-S011])"
  "**不是所有酒都醒**——只老酒去沉淀 / 年轻封闭的高单宁酒增氧,且拔塞「透气」瓶颈面积太小几乎不增氧、要真醒必须倒进醒酒器。案例(case):「这支必须醒满 X 小时」「所有酒都要醒」是被资深拒绝的话术,醒多久高度个案、多数酒开瓶即饮 (evidence: [T03-S007, T06-S035])"
  "默认是被资深拒绝的错位包装、回到机理。案例(case):红酒头疼真因更可能是 quercetin 抑制 ALDH 而非 sulfites(白酒含等量 sulfites 却少致头疼);「投资酒稳赚」是诈骗高发话术(伪造产地 / 超收 / 假瓶) (evidence: [T06-S006, T06-S033])"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "general-playbook-decision"
fi
